\textit{Source: Ancona, arXiv:1806.03216, §2.}
  Fix a base field \(k\). A \emph{variety} over \(k\) is a smooth, projective and
  geometrically connected scheme over \(k\).

\textit{Source: Ancona, arXiv:1806.03216, §2.}
  The \emph{classical realizations} are the following functors into graded vector
  spaces:
  \begin{itemize}
    \item Betti realization \(R_B : \CHM(\C)_{\Q} \to \GrVec_\Q\);
    \item \(\ell\)-adic realization (\(\ell\) invertible in \(k\))
      \(R_\ell : \CHM(k)_{\Q} \to \GrVec_{\Q_\ell}\);
    \item de Rham realization (\(k\) of characteristic zero)
      \(R_\dR : \CHM(k)_{\Q} \to \GrVec_{k}\);
    \item crystalline realization (\(k\) perfect of positive characteristic)
      \(R_\crys : \CHM(k)_{\Q} \to \GrVec_{\Frac(W(k))}\).
  \end{itemize}
  In their enriched form these functors land in Hodge structures (\(R_B\)),
  Galois representations (\(R_\ell\)), filtered vector spaces (\(R_\dR\)) and
  spaces with an absolute Frobenius action (\(R_\crys\)).

\textit{Source: Ancona, arXiv:1806.03216, §2.}
  An algebraic class \(\alpha\) of a motive \(T\) is \emph{numerically trivial}
  if \(\beta \circ \alpha = 0\) for every \(\beta \in \Hom(T, \one)\). Two
  algebraic classes are \emph{numerically equivalent} if their difference is
  numerically trivial. This recovers the classical notion of numerical
  equivalence.

\textit{Source: Ancona, arXiv:1806.03216, §3.}
  For \(n \leq d\) the \emph{motivic pairing}
  \[\langle \cdot, \cdot \rangle_{n,\mathrm{mot}} : \hh^n(X) \otimes \hh^{n}(X)
    \longrightarrow \one(-n)\]
  is defined recursively on \(n\) by modifying the adjunction pairing \(q_n\) of
  the previous remark, as follows:
  \begin{itemize}
    \item the Lefschetz decomposition
      \(\hh^{n}(X) = \hh^{n,\prim}(X) \oplus \hh^{n-2}(X)(-1)\) is required to be
      orthogonal;
    \item on the summand \(\hh^{n-2}(X)(-1)\) one imposes the equality
      \(\langle \cdot, \cdot \rangle_{n,\mathrm{mot}} =
      \langle \cdot, \cdot \rangle_{n-2,\mathrm{mot}}(-2)\);
    \item on the primitive part \(\hh^{n,\prim}(X)\) one sets
      \(\langle \cdot, \cdot \rangle_{n,\mathrm{mot}} = (-1)^{n(n+1)/2} q_n\).
  \end{itemize}

\textit{Source: Ancona, arXiv:1806.03216, §3.}
  The standard conjecture of Hodge type (\cref{conj:hodge-type}) holds for abelian
  fourfolds in positive characteristic.

\textit{Source: Ancona, arXiv:1806.03216, §4.}
  Let \(T\) be a motive of abelian type of dimension \(d\), and let
  \[V_Z = V_Z(T) = \Hom_{\NUM(k)_\Q}(\one, T)\]
  be its space of algebraic classes modulo numerical equivalence. Then
  \[\dim_\Q V_Z \le d.\]
  Moreover, if \(\dim_\Q V_Z = d\), then:
  \begin{enumerate}
    \item all realizations of \(T\) are spanned by algebraic classes;
    \item numerical equivalence on \(\Hom_{\CHM(k)_\Q}(\one, T)\) coincides with
      homological equivalence (for all cohomologies);
    \item if \(L\) is the coefficient field of the realization \(R\), then
      \(V_Z \otimes_\Q L = R(T)\).
  \end{enumerate}

\textit{Source: Ancona, arXiv:1806.03216, §6.}
  There exists a polarization on the abelian scheme \(\mathcal{A}\) of
  \cref{thm:honda-tate} for which the CM-structure is \(*\)-stable.

\textit{Source: Ancona, arXiv:1806.03216, §6.}
  The decompositions of \(\hh(A \times_k k')\) in \cref{prop:cm-decomposition}
  lift to decompositions of \(\hh(\mathcal{A}) \in \CHM(W)\). Moreover, if the
  CM-structure of \(A\) is \(*\)-stable (and the polarization lifts as well),
  then the orthogonality statement of \cref{prop:cm-decomposition} holds in
  \(\CHM(W)\) too.

\textit{Source: Ancona, arXiv:1806.03216, §7.}
  We suppose that all the algebraic classes
  \(\mathcal{Z}^*_\num(A_{\bar k})_\Q\) are defined over \(k\).

\textit{Source: Ancona, arXiv:1806.03216, §7.}
  The following hold.
  \begin{enumerate}
    \item If \(I\) is an exotic subset, then the pair \((I, \bar I)\) is a
      partition of \(\Sigma\).
    \item Any \(\Gal(\bar\Q/\Q)\)-conjugate of an exotic subset is again exotic.
    \item Any exotic motive is even-dimensional.
  \end{enumerate}

\textit{Source: Ancona, arXiv:1806.03216, §7.}
  Under \cref{def:exotic-assumption}, two exotic subsets cannot intersect in
  exactly two elements.

\textit{Source: Ancona, arXiv:1806.03216, \S10.}
  There are canonical identifications, commuting with all the extra structure:
  \begin{align}
    (V_{B,p}, q_{B,p}) &= [(V_{Z,p}, q_{Z,p}) \otimes \Bcrys]^{\varphi=\id}
      \cap \Fil^0[(V_{Z,p}, q_{Z,p}) \otimes \BdR], \\
    (V_{B,p}, q_{B,p}) \otimes \Bcrys &= (V_{Z,p}, q_{Z,p}) \otimes \Bcrys, \\
    (V_{B,p}, q_{B,p}) \otimes \BdR &= (V_{Z,p}, q_{Z,p}) \otimes \BdR.
  \end{align}
  Moreover, under these identifications, the equality of \(\Q_p\)-algebras
  \[\End_{\Gal_K}(V_{B,p}) = \End_{\varphi,\Fil^*}(V_{Z,p} \otimes \Frac(W(k)))\]
  holds.

\textit{Source: Ancona, arXiv:1806.03216, \S10.}
  Under \cref{ass:i-positive}, the \(\Q_p\)-algebra
  \(\End_{\Gal_K}(V_{B,p})\) is a field \(F\) with \([F : \Q_p] = 2\). Moreover,
  for all \(v \in V_{B,p}\) and \(f \in F\),
  \begin{equation}
    q_{B,p}(f \cdot v) = N_{F/\Q_p}(f)\, q_{B,p}(v).
  \end{equation}

\textit{Source: Ancona, arXiv:1806.03216, \S10.}
  Let \(F\) be the field of \cref{prop:endo-field}. Then \(F\) acts on
  \(V_{Z,p}\), the first identification of \cref{cor:crys-identifications} is
  \(F\)-equivariant, and for all \(v \in V_{Z,p}\) and \(f \in F\),
  \begin{equation}
    q_{Z,p}(f \cdot v) = N_{F/\Q_p}(f)\, q_{Z,p}(v).
  \end{equation}

\textit{Source: Ancona, arXiv:1806.03216, \S11.}
  The \(F\)-vector space \(P_i(F)\) has dimension one. A nonzero
  \(\lambda_i \in P_i\) satisfies:
  (1) \(\lambda_i \cdot \varphi(\lambda_i) \in \Q_p^*\);
  (2) \(\lambda_i\) and \(\varphi(\lambda_i)\) are invertible in \(\Bcrys\);
  (3) \(\lambda_i \in \Fil^i \BdR \setminus \Fil^{i+1} \BdR\);
  (4) \(\varphi(\lambda_i) \in \Fil^{-i} \BdR \setminus \Fil^{-i+1} \BdR\).

\textit{Source: Ancona, arXiv:1806.03216, \S11.}
  The \(F\)-vector space \(P_i(F)\) has dimension one. A nonzero
  \(\lambda_i \in P_i\) satisfies:
  (1) \(\lambda_i \cdot \sigma(\lambda_i) \in \Q_p^*\);
  (2) \(\lambda_i\) and \(\sigma(\lambda_i)\) are invertible in \(B_{\crys,F}\);
  (3) \(\lambda_i \in \Fil^i \BdR \setminus \Fil^{i+1} \BdR\);
  (4) \(\sigma(\lambda_i) \in \Fil^{-i} \BdR \setminus \Fil^{-i+1} \BdR\).

\textit{Source: Ancona, arXiv:1806.03216, \S11.}
  The \(F\)-vector subspaces \(P_i, Q \subset B_{\crys,F}\) of
  \cref{def:periods-ram} and \cref{def:Q-ram} coincide and have dimension one.

\textit{Source: Ancona, arXiv:1806.03216, \S12.}
  There is an element \(t_2 \in \Bcrys\) with:
  (1) \(t_2 \in \Fil^1 \BdR \setminus \Fil^2 \BdR\);
  (2) \(\varphi(t_2) \in \Fil^0 \BdR \setminus \Fil^1 \BdR\);
  (3) \(\varphi^2(t_2) = p \cdot t_2\);
  (4) both \(t_2\) and \(\varphi(t_2)\) are invertible in \(\Bcrys\).

\textit{Source: Ancona, arXiv:1806.03216, \S12.}
  For each uniformizer \(\pi \in F\) there is an element
  \(t_\pi \in B_{\crys,F}\) with:
  (1) \(t_\pi \in \Fil^1 \BdR \setminus \Fil^2 \BdR\);
  (2) \(\sigma(t_\pi) \in \Fil^0 \BdR \setminus \Fil^1 \BdR\);
  (3) \(\varphi(t_\pi) = \pi \cdot t_\pi\);
  (4) both \(t_\pi\) and \(\sigma(t_\pi)\) are invertible in \(B_{\crys,F}\).

\textit{Source: Ancona, arXiv:1806.03216, \S12.}
  For each uniformizer \(\pi \in F\) there is an element
  \(t_{2,\pi} \in B_{\crys,F}\) with:
  (1) \(t_{2,\pi} \in \Fil^1 \BdR \setminus \Fil^2 \BdR\);
  (2) \(\sigma(t_{2,\pi}), \varphi(t_{2,\pi}), \varphi\sigma(t_{2,\pi}) \in
  \Fil^0 \BdR \setminus \Fil^1 \BdR\);
  (3) \(\varphi^2(t_{2,\pi}) = \pi \cdot t_{2,\pi}\);
  (4) \(t_{2,\pi}, \sigma(t_{2,\pi}), \varphi(t_{2,\pi}), \varphi\sigma(t_{2,\pi})\)
  are invertible in \(B_{\crys,F}\).

\textit{Source: Ancona, arXiv:1806.03216, \S12.}
  For \(p = 2\) and \(F = \Q_2(\sqrt 3)\) there is an element
  \(t_f \in B_{\crys,F}\) with:
  (1) \(t_f \in \Fil^1 \BdR \setminus \Fil^2 \BdR\);
  (2) \(\sigma(t_f), \varphi(t_f), \varphi\sigma(t_f) \in \Fil^0 \BdR \setminus
  \Fil^1 \BdR\);
  (3) \(\varphi^2(t_f) = (1 - \sqrt{-1}) \cdot t_f\);
  (4) \(t_f, \sigma(t_f), \varphi(t_f), \varphi\sigma(t_f)\) are invertible in
  \(B_{\crys,F}\).

nodes.proof_tex:
\uses{prop:lubin-tate-wild2, prop:periods-ram-dim}
Direct calculation from \cref{prop:lubin-tate-wild2}: the combination of
\(t_f, \varphi(t_f), \sigma(t_f), \varphi\sigma(t_f)\) makes \(\varphi^2\) act
trivially and, with the factor \(\alpha\), \(\varphi(\lambda_i) = \lambda_i\);
the filtration steps give \(\lambda_i \in P_i(F)\) (\cref{def:periods-ram}) and
\(\lambda_i \cdot \sigma(\lambda_i) = (\alpha\,\sigma(\alpha))^i\).

